// WF1 v9.1 - Extract ALL items và filter theo email limit
// Trả về ARRAY items cho loop processing

const results = $input.first().json.results || [];
const today = new Date().toISOString().split('T')[0];

console.log(`[WF1 v9.1] Found ${results.length} clarifications`);

const outputItems = [];

for (const page of results) {
  const props = page.properties;

  // Basic info
  const id = page.id;
  const tieuDe = props['Tiêu đề']?.title?.[0]?.plain_text || 'Không có tiêu đề';

  // Email limiting
  const soLanGui = props['📧 Số lần gửi']?.number || 0;
  const ngayGuiRaw = props['📅 Ngày gửi gần nhất']?.date?.start || null;
  const ngayGuiGanNhat = ngayGuiRaw ? ngayGuiRaw.split('T')[0] : null;

  const isToday = ngayGuiGanNhat === today;
  const canSend = !isToday || soLanGui < 2;

  if (!canSend) {
    console.log(`[WF1 v9.1] SKIP: ${tieuDe} - Đã gửi ${soLanGui} lần hôm nay`);
    continue;
  }

  // Extract all properties
  const nguon = props['Nguồn']?.select?.name || '';
  const ngayNhan = props['Ngày nhận']?.date?.start || '';
  const noiDungGoc = props['Nội dung gốc']?.rich_text?.[0]?.plain_text || '';
  const t2NhiemVu = props['T2 - NHIỆM VỤ']?.rich_text?.[0]?.plain_text || '';
  const t3ChiTieu = props['T3 - CHỈ TIÊU']?.rich_text?.[0]?.plain_text || '';
  const t4ThoiHan = props['T4 - THỜI HẠN']?.date?.start || '';
  const ghiChu = props['Ghi chú']?.rich_text?.[0]?.plain_text || '';

  // Email resolution
  const emailDauMoi = props['📧 Email đầu mối']?.email || '';
  const hrRelation = props['👤 Người nhận chỉ đạo (HR)']?.relation || [];
  const hrId = hrRelation.length > 0 ? hrRelation[0].id : null;

  // Outcomes relation for T3
  const outcomesRelation = props['Kết quả mong đợi']?.relation || [];
  const outcomeId = outcomesRelation.length > 0 ? outcomesRelation[0].id : null;

  outputItems.push({
    json: {
      id,
      tieuDe,
      nguon,
      ngayNhan,
      noiDungGoc,
      t2NhiemVu,
      t3ChiTieu,
      t4ThoiHan,
      ghiChu,
      emailDauMoi,
      hrId,
      outcomeId,
      soLanGui,
      newSoLanGui: isToday ? soLanGui + 1 : 1,
      todayDate: today,
      startTime: Date.now()
    }
  });
}

console.log(`[WF1 v9.1] Eligible items: ${outputItems.length}`);

// Return array of items for loop processing
if (outputItems.length === 0) {
  return [{ json: { noItems: true, message: 'No eligible clarifications' } }];
}

return outputItems;

// WF1 v9.1 - Fetch Outcome T3 if available (ALL IN ONE NODE)
// Simplified: No more Merge nodes needed

const item = $input.first().json;
let t3Final = item.t3ChiTieu;
let t3Source = 'Clarification';
let outcomeName = '';

// If has Outcome relation, we'll fetch it in next node
// Just pass through with flag
return {
  json: {
    ...item,
    needsOutcomeFetch: !!item.outcomeId,
    t3Final,
    t3Source,
    outcomeName
  }
};

// Merge T3 from Outcome
const prevItem = $('IF: Cần fetch Outcome?').first().json;
const outcome = $input.first().json;

// Get T3 from Outcome's "Tiêu chí thành công" field
const tieuChiThanhCong = outcome.properties?.['Tiêu chí thành công']?.rich_text?.[0]?.plain_text || '';
const outcomeName = outcome.properties?.['Kết quả mong đợi']?.title?.[0]?.plain_text || '';

// Use Outcome's T3 if available, otherwise keep original
const t3Final = tieuChiThanhCong || prevItem.t3ChiTieu;
const t3Source = tieuChiThanhCong ? 'Outcome' : 'Clarification';

console.log(`[WF1 v9.1] Outcome T3: ${tieuChiThanhCong || '(empty)'}, Final T3: ${t3Final || '(empty)'}`);

return {
  json: {
    ...prevItem,
    t3Final,
    t3Source,
    outcomeName
  }
};

// No Outcome - pass through with original T3
const item = $input.first().json;
console.log(`[WF1 v9.1] No Outcome for: ${item.tieuDe}`);
return {
  json: {
    ...item,
    t3Final: item.t3ChiTieu,
    t3Source: 'Clarification (no Outcome)'
  }
};

// WF1 v9.1 - Resolve Email (ALL IN ONE - NO MERGE)
// This handles both HR lookup and direct email

const item = $input.first().json;
let resolvedEmail = '';
let resolvedName = '';
let emailSource = '';
let needsHrFetch = false;

// Priority 1: Direct email field
if (item.emailDauMoi) {
  resolvedEmail = item.emailDauMoi;
  emailSource = 'Direct';
} 
// Priority 2: Need HR lookup
else if (item.hrId) {
  needsHrFetch = true;
  emailSource = 'HR (pending)';
}
// Priority 3: Fallback
else {
  resolvedEmail = 'vynnl@esuhai.com';
  resolvedName = 'HR Vy';
  emailSource = 'Fallback';
}

return {
  json: {
    ...item,
    resolvedEmail,
    resolvedName,
    emailSource,
    needsHrFetch
  }
};

// Resolve email from HR record
const prevItem = $('IF: Cần HR Lookup?').first().json;
const hr = $input.first().json;

const hrName = hr.properties?.['Họ và tên']?.title?.[0]?.plain_text || 
               hr.properties?.['Tên']?.title?.[0]?.plain_text || '';
const hrEmail = hr.properties?.['Email']?.email || 
                hr.properties?.['📧 Email']?.email || '';

let resolvedEmail, resolvedName, emailSource;

if (hrEmail) {
  resolvedEmail = hrEmail;
  resolvedName = hrName;
  emailSource = 'HR';
} else {
  // Fallback if HR has no email
  resolvedEmail = 'vynnl@esuhai.com';
  resolvedName = hrName || 'HR Vy';
  emailSource = 'Fallback (HR no email)';
}

return {
  json: {
    ...prevItem,
    resolvedEmail,
    resolvedName,
    emailSource
  }
};

// Direct/Fallback email - no HR fetch needed
const item = $input.first().json;
console.log(`[WF1 v9.1] Email resolved: ${item.resolvedEmail} (${item.emailSource})`);
return { json: item };

// WF1 v9.1 - Build Prefill URL cho Form CŨ
const item = $input.first().json;

// Entry IDs cho Form CŨ (verified)
const entryIds = {
  maClarification: '1684171280',
  nguonChiDao: '1878008034',
  ngayNhanChiDao: '1953342780',
  noiDungGoc: '1839616630',
  dauMoiT1: '649583359',
  t2NhiemVu: '1319518938',
  t3ChiTieu: '1910876946',
  t4ThoiHan: '1661283634',
  ghiChu: '1985703119'
};

const formId = '1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw';
const baseUrl = `https://docs.google.com/forms/d/e/${formId}/viewform?usp=pp_url`;

// Use t3Final (from Outcome if available)
const t3Value = item.t3Final || item.t3ChiTieu || '';

// Build prefill params
const params = [
  `entry.${entryIds.maClarification}=${encodeURIComponent(item.id || '')}`,
  `entry.${entryIds.nguonChiDao}=${encodeURIComponent(item.nguon || '')}`,
  `entry.${entryIds.ngayNhanChiDao}=${encodeURIComponent(item.ngayNhan || '')}`,
  `entry.${entryIds.noiDungGoc}=${encodeURIComponent(item.noiDungGoc || '')}`,
  `entry.${entryIds.dauMoiT1}=${encodeURIComponent(item.resolvedName || '')}`,
  `entry.${entryIds.t2NhiemVu}=${encodeURIComponent(item.t2NhiemVu || '')}`,
  `entry.${entryIds.t3ChiTieu}=${encodeURIComponent(t3Value)}`,
  `entry.${entryIds.t4ThoiHan}=${encodeURIComponent(item.t4ThoiHan || '')}`,
  `entry.${entryIds.ghiChu}=${encodeURIComponent(item.ghiChu || '')}`
].join('&');

const prefillUrl = `${baseUrl}&${params}`;

// Email content
const lanGui = item.newSoLanGui || 1;
const greeting = item.resolvedName ? `Chào ${item.resolvedName},` : 'Chào Anh/Chị,';

const emailSubject = `[Lần ${lanGui}] Yêu cầu xác nhận chỉ đạo: ${item.tieuDe}`;
const emailBody = `${greeting}

Bạn nhận được yêu cầu xác nhận chỉ đạo từ hệ thống CEO Directive.

📋 Thông tin chỉ đạo:
- Tiêu đề: ${item.tieuDe}
- Nguồn: ${item.nguon || 'Chưa xác định'}
- Ngày nhận: ${item.ngayNhan || 'Chưa xác định'}

🔗 Vui lòng xác nhận tại đây:
${prefillUrl}

⚠️ Lưu ý:
- Kiểm tra thông tin đã điền sẵn
- Bổ sung T2, T3, T4 nếu còn thiếu
- Tick xác nhận và gửi form

Trân trọng,
Hệ thống CEO Directive - EsuhaiGroup`;

return {
  json: {
    ...item,
    prefillUrl,
    emailSubject,
    emailBody,
    emailTo: item.resolvedEmail,
    emailCc: 'hoangkha@esuhai.com'
  }
};

